INSERT INTO jobs (job_name, industry, city, company_type, salary_min, salary_max, skills, soft_skills, is_fresh_friendly, friendly_level, jd_content, core_duties, education, major, experience, post_type, bonus_skills, salary_range, post_time, apply_deadline, jd_link, post_category, party_label) VALUES ('hrbp经理 - 泰安（社招）', '其他', '泰安', '民营企业', 7000, 10000, '1. 熟练使用办公软件，具备制度搭建与流程优化能力；2. 具备文化体系搭建与落地能力；3. 具备跨部门项目管理与推进能力', '1. 有强烈的目标感和责任感，具备领导团队与决策能力；2. 优秀的团队管理能力、跨部门协同能力、沟通能力和逻辑分析判断能力；3. 较强的自驱力、执行力和学习能力，能快速适应；4. 具备大局观，做事灵活，能融会变通，换位思考', 0, '一般', '1. 执行现有的文化落地流程，发现问题并提出改进方案，落地后取得较好结果；2. 推动各部门重要事项进度，根据公司需要做出相应调整和优化；3. 管理公司跨部门协作，确保公司运营效率和业务增长；4. 建立健全各部门的文化管理机制，包括人员架构、业务流程和各项规章制度等；5. 统筹政委中心工作开展，负责文化落地、价值观推行，发现文化管理问题并改进提升；6. 统筹公司文化考核标准的出具和优化，通过文化建设提升团队凝聚力和业绩增长；7. 建立和完善公司文化管理体系，优化管理流程，推动各项目按计划完成', 'OD 组织发展支持、员工关系支持、薪酬绩效支持', '大专及以上', '人力资源、行政管理等相关专业优先', '3-5年，300人以上企业任职经验，有3年以上人资总监/政委相关管理工作经验', '社招（应届生可投）', '有人力资源管理师相关证书；有大型企业文化建设/政委体系搭建经验', '7k-10k/月', '46112', NULL, 'BOSS直聘平台获取', 'HRBP类', '甲方（企业自有 HR 岗）'), ('HRBP经理 - 乐山（社招）', '医疗健康 / 生物', '乐山', '民营企业', 10000, 15000, '1. 熟练使用办公软件，具备人力资源数据分析与报告输出能力；2. 精通人力资源全模块工作，熟悉相关法律法规；3. 具备人才规划、组织架构设计与优化能力', '1. 有较强的执行能力及抗压能力、团队协作精神及较强的服务意识；2. 具备优秀的跨部门沟通协调能力与业务理解能力；3. 目标导向，具备较强的项目管理与团队管理能力', 0, '一般', '1. 与业务大区建立紧密合作关系，跟进业务战略与运营情况，定期参加业务重要会议，提供人力资源视角的见解和建议；2. 根据业务部门战略规划，制定匹配的人力资源计划，保障人力工作有效支持业务发展；3. 分析业务部门人力需求，参与组织架构设计与优化；4. 协同业务进行人才规划，制定招聘策略并参与关键岗位招聘，保障业务用人需求；5. 协助业务部门开展绩效管理工作，共同制定考核标准，定期开展绩效评估，推动绩效改进落地；6. 识别高潜人才，建立人才储备库，为企业长期发展提供人才保障；7. 协助处理员工关系问题，提供及时有效的解决方案，维护良好的员工关系；8. 推动企业文化在业务部门落地，组织员工活动，增强员工归属感与凝聚力；9. 整理分析业务部门人力相关数据，为业务决策提供数据支持；10. 领导管理HRBP团队，分配工作任务，制定团队培训发展计划，提升团队整体业务能力；11. 参与组织变革、人才盘点、员工激励等人力项目在业务部门的落地实施；12. 确保人力政策、制度在业务部门有效执行，保障人力管理工作符合法律法规要求', '招聘全流程执行、渠道拓展与运营、薪酬绩效支持、员工关系支持、OD 组织发展支持、招聘数据分析', '本科及以上', '人力资源、工商管理等相关专业优先', '3-5年，5年以上人力资源工作经验，其中至少3年HRBP相关工作经验，需接受四川范围内出差', '社招（应届生可投）', '有人力资源管理师相关证书；有医疗健康行业HRBP管理经验；有千人团队BP经验', '10k-15k/月', '46112', NULL, 'BOSS直聘平台获取', 'HRBP类', '甲方（企业自有 HR 岗）'), ('hrbp经理 - 郴州（社招）', '制造', '郴州', '民营企业', 10000, 15000, '1. 熟练使用办公软件，具备人力资源全流程管理能力；2. 熟悉当地地区及企业关于合同管理、薪金制度、用人机制、保险福利待遇、培训等方面的法律法规及政策；3. 对人力资源管理模式有系统的了解和丰富的实践经验，能够指导各个职能模块的工作', '1. 具有解决复杂问题的能力，很强的计划性和实施执行的能力，有能力建立、整合不同的工作团队；2. 很强的激励、沟通、协调、团队领导能力，责任心、事业心、承压能力强；3. 具备良好的保密意识与职业素养', 0, '一般', '1. 完善修正公司人力资源体系；2. 负责组织起草、修改和完善人力资源相关管理制度和工作流程；3. 负责招聘、培训、薪酬、考核、员工关系等人力资源日常管理事宜；4. 负责人事政策、制度与流程的拟订与督导实施；5. 负责公司员工的管理、指导、培训及评估，推动公司人才梯队建设；6. 负责新公司日常事务管理工作，完成员工薪酬核算、考核、激励及部门资金预算控制等人事与行政工作；7. 根据公司业务要求，做好营销、职能等环节的会议主持工作；8. 根据公司需求，做好与当地政府关系的协调与处理；9. 及时完成领导安排的各项工作，做好工作的及时性汇报', '招聘全流程执行、薪酬绩效支持、员工关系支持、OD 组织发展支持、招聘数据分析', '大专及以上', '人力资源、管理或相关专业优先', '5-10年，五年以上人力资源经理工作经验，家具家居建材行业相关经验优先', '社招（应届生可投）', '有人力资源管理师相关证书；有家具家居建材行业HR管理经验', '10k-15k/月', '46112', NULL, 'BOSS直聘平台获取', 'HRBP类', '甲方（企业自有 HR 岗）'), ('hrbp经理 - 商丘（社招）', '其他', '商丘', '民营企业', 6000, 11000, '熟练操作office、WPS等基础办公软件', '具有良好的沟通表达能力、细心认真、踏实稳重、责任心强、有条理', 1, '友好', '1. 负责公司各岗位人员招聘及后续人员跟进；2. 负责公司人员各种手续办理；3. 负责公司招聘渠道拓展和管理，利用各种渠道满足公司人才需求，熟练掌握网络发帖技巧；4. 完成上级领导交办的其它事项以及协助处理公司各项行政工作', '招聘全流程执行、渠道拓展与运营、员工关系支持', '大专及以上', '无强制专业限制', '1年以内，年龄20+', '社招（应届生可投）', '有人力资源管理师相关证书；有HRBP/招聘相关经验', '6k-11k/月', '46112', NULL, 'BOSS直聘平台获取', 'HRBP类', '甲方（企业自有 HR 岗）'), ('薪酬福利实习生 - 北京（实习）', '人力资源服务 / 咨询', '北京', '国企 / 央企', 120, 150, '熟练使用Word、Excel等办公软件', '良好的数据收集能力和沟通协调能力，做事细致，积极主动，有责任心', 1, '极度友好', '1. 协助审核、汇总考勤相关数据；2. 协助进行薪酬福利计算及个人所得税、成本的申报工作，确保信息准确；3. 协助进行社保公积金、公司福利相关材料整理、审核；4. 协助解答员工薪酬福利相关咨询；5. 完成团队分配的其他工作', '薪酬绩效支持、员工关系支持、招聘数据分析', '本科及以上', '专业不限，人力资源管理相关专业优先', '本科或研究生在读，每周出勤3天以上，可实习4个月，可长期实习者优先', '日常实习', '有人力资源相关实习经验；有薪酬核算相关经验', '120-150元/天', '46112', '46142', 'https://www.shixiseng.com/intern/inn_4eyztjshbbq?pcm=pc_SearchList', '薪酬绩效类', '甲方（企业自有 HR 岗）');